import React, { useState } from 'react';
import { motion } from 'framer-motion';
import Home from './Home';

function App() {
  const [lang, setLang] = useState('English');
  
  return (
    <div className="min-h-screen bg-green-50 font-sans text-gray-900">
      <nav className="p-4 bg-white shadow-md flex justify-between items-center">
        <h1 className="text-2xl font-black text-green-700">KisanMarket</h1>
        <select 
          onChange={(e) => setLang(e.target.value)}
          className="bg-green-100 p-2 rounded-lg font-bold"
        >
          <option>English</option>
          <option>हिन्दी</option>
          <option>मराठी</option>
        </select>
      </nav>
      <Home lang={lang} />
    </div>
  );
}

export default App;
